const canvas = document.getElementById('game');
const ctx = canvas.getContext('2d');

const playerPaddle = {
    x: 10,
    y: 150,
    width: 15,
    height: 80,
    speed: 5
};

const keys = {};

// Handle user input
window.addEventListener('keydown', (event) => {
    const key = event.key.toLowerCase();
    if (key === 'w' || key === 's') {
        keys[key] = true;
    }
});

window.addEventListener('keyup', (event) => {
    const key = event.key.toLowerCase();
    if (key === 'w' || key === 's') {
        keys[key] = false;
    }
});

/**
 * Updates game logic, including paddle movement and collision boundaries.
 */
function update() {
    // Move paddle up
    if (keys['w']) {
        playerPaddle.y -= playerPaddle.speed;
    }

    // Move paddle down
    if (keys['s']) {
        playerPaddle.y += playerPaddle.speed;
    }

    // Clamp paddle within canvas vertical bounds
    if (playerPaddle.y < 0) {
        playerPaddle.y = 0;
    }

    const bottomBoundary = canvas.height - playerPaddle.height;
    if (playerPaddle.y > bottomBoundary) {
        playerPaddle.y = bottomBoundary;
    }
}

/**
 * Renders all game objects to the canvas.
 */
function draw() {
    // Clear the canvas before drawing
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw player paddle
    ctx.fillStyle = 'white';
    ctx.fillRect(
        playerPaddle.x,
        playerPaddle.y,
        playerPaddle.width,
        playerPaddle.height
    );
}

/**
 * Main game loop running at the monitor's refresh rate.
 */
function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

// Initiate the game
gameLoop();
```

